// src/components/layouts/UserLayout.jsx
import React, { useState } from "react";

// Existing pages
import UserDashboard from "../dashboards/UserDashboard";
import MySystemDetail from "..//MySystemDetail";

/*
  UserLayout.jsx
  -------------------------
  Simple, friendly layout for non-technical users.
  - Permanent shell (header, nav, main, footer)
  - Child pages rendered inside via internal state (no router)
  - Minimal UI, clear language, no technical jargon
*/

/* --------------------------
   Support Request Page
   -------------------------- */
function SupportRequestPage({ user }) {
  const [message, setMessage] = useState("");
  const [submitted, setSubmitted] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState("");

  const submit = (e) => {
    e.preventDefault();
    setError("");

    if (!message.trim()) {
      setError("Please describe the issue before submitting.");
      return;
    }

    if (message.trim().length < 10) {
      setError("Please provide more details (at least 10 characters).");
      return;
    }

    setIsSubmitting(true);

    setTimeout(() => {
      console.log("Support request submitted:", {
        from: user.email,
        message,
      });
      setIsSubmitting(false);
      setSubmitted(true);
    }, 1000);
  };

  const reset = () => {
    setMessage("");
    setSubmitted(false);
    setError("");
  };

  return (
    <div className="max-w-2xl space-y-6">
      <div>
        <h2 className="text-2xl font-semibold text-slate-900 mb-2">
          Support Request
        </h2>
        <p className="text-sm text-slate-600">
          Tell us what's wrong in plain language. A technician will help you.
        </p>
      </div>

      {!submitted ? (
        <div className="bg-white border rounded-lg p-6 space-y-4">
          <textarea
            value={message}
            onChange={(e) => {
              setMessage(e.target.value);
              setError("");
            }}
            rows={7}
            className="w-full border rounded-lg p-3 text-sm"
            placeholder="Describe the issue you are facing..."
            disabled={isSubmitting}
          />

          {error && (
            <div className="bg-red-50 border border-red-200 text-red-700 p-3 rounded text-sm">
              {error}
            </div>
          )}

          <div className="flex gap-3">
            <button
              onClick={submit}
              disabled={isSubmitting}
              className="px-5 py-2 bg-blue-600 text-white rounded-lg text-sm"
            >
              {isSubmitting ? "Submitting..." : "Submit Request"}
            </button>
            <button
              onClick={() => setMessage("")}
              disabled={isSubmitting}
              className="px-4 py-2 border rounded-lg text-sm"
            >
              Clear
            </button>
          </div>
        </div>
      ) : (
        <div className="bg-white border rounded-lg p-8 text-center">
          <div className="text-3xl mb-3">✅</div>
          <h3 className="text-lg font-semibold">Request Submitted</h3>
          <p className="text-sm text-slate-600 mt-2">
            A technician will review your request shortly.
          </p>
          <button
            onClick={reset}
            className="mt-4 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm"
          >
            Submit Another
          </button>
        </div>
      )}
    </div>
  );
}

/* ---------------------------------------
   Main UserLayout component
   --------------------------------------- */
export default function UserLayout({ userData, onLogout }) {
  const [active, setActive] = useState("dashboard");

  const user = {
    firstName: userData?.email?.split("@")[0] || "User",
    email: userData?.email || "user@example.com",
    avatar: userData?.email?.[0]?.toUpperCase() || "U",
  };

  const nav = [
    { id: "dashboard", label: "Dashboard", icon: "📊" },
    { id: "mysystem", label: "My System", icon: "💻" },
    { id: "support", label: "Support Request", icon: "💬" },
  ];

  const renderContent = () => {
    switch (active) {
      case "dashboard":
        return <UserDashboard user={user} onNavigate={setActive} />;
      case "mysystem":
        return <MySystemDetail />;
      case "support":
        return <SupportRequestPage user={user} />;
      default:
        return <UserDashboard user={user} onNavigate={setActive} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-blue-600 text-white rounded-lg flex items-center justify-center font-bold">
              M
            </div>
            <div>
              <div className="font-semibold text-slate-900">MaintenanceAI</div>
              <div className="text-xs text-slate-500">Employee Portal</div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="text-sm text-slate-600 hidden sm:block">
              Signed in as <strong>{user.firstName}</strong>
            </div>
            <div className="w-8 h-8 bg-blue-500 text-white rounded-full flex items-center justify-center text-sm font-semibold">
              {user.avatar}
            </div>
            <button
              onClick={onLogout}
              className="text-sm text-red-600 border border-red-200 px-3 py-1 rounded-lg"
            >
              Logout
            </button>
          </div>
        </div>
      </header>

      {/* Navigation */}
      <nav className="bg-white border-b">
        <div className="max-w-7xl mx-auto px-6 flex gap-6 h-12 items-center">
          {nav.map((n) => (
            <button
              key={n.id}
              onClick={() => setActive(n.id)}
              className={`flex items-center gap-2 text-sm px-3 py-2 border-b-2 ${
                active === n.id
                  ? "border-blue-600 text-blue-700 font-medium"
                  : "border-transparent text-slate-600 hover:text-slate-900"
              }`}
            >
              <span>{n.icon}</span>
              {n.label}
            </button>
          ))}
        </div>
      </nav>

      {/* Content */}
      <main className="flex-1 overflow-y-auto">
        <div className="max-w-7xl mx-auto px-6 py-6">
          {renderContent()}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t">
        <div className="max-w-7xl mx-auto px-6 py-4 text-sm text-slate-600 flex justify-between">
          <span>Need help? support@company.com</span>
          <span>© {new Date().getFullYear()} MaintenanceAI</span>
        </div>
      </footer>
    </div>
  );
}
